#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int ci[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &ci[i]);
        }
        long long dp[n + 1];
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            if (ci[i] == 0) {
                dp[i + 1] = dp[i];
            } else {
                dp[i + ci[i] + 1] = (dp[i + ci[i] + 1] + dp[i]) % MOD;
            }
        }
        printf("%lld\n", dp[n]);
    }
    return 0;
}

