                if (ci[i] == 0) {
                    dp[i + 1] = dp[i];
                } else {
                    dp[i + ci[i] + 1] = (dp[i + ci[i] + 1] + dp[i]) % 1000000007;
                }
            }
            System.out.println(dp[n]);
        }
    }
